  xferSave.xferBool(false);
  xferSave.xferVersion(1);
  xferSave.xferUnsignedInt(framesRemaining);
  xferSave.xferObjectID(0);
  xferSave.xferCoord3D({ x: 0, y: 0, z: 0 });
