function createSourceObjectBlockData(
  includeHelperModules = false,
  extraModules: Array<{ identifier: string; blockData: Uint8Array }> = [],
  options: {
    objectId?: number;
    templateName?: string;
    internalName?: string;
    teamId?: number;
    drawableId?: number;
    originalTeamName?: string;
    completedUpgradeNames?: string[];
  } = {},
): Uint8Array {
  const state = createEmptySourceMapEntitySaveState();
  const objectId = options.objectId ?? 7;
  const templateName = options.templateName ?? 'RuntimeTank';
  state.objectId = objectId;
  state.teamId = options.teamId ?? 3;
  state.drawableId = options.drawableId ?? 9;
  state.internalName = options.internalName ?? `UNIT_${objectId.toString().padStart(3, '0')}`;
  state.originalTeamName = options.originalTeamName ?? 'TEAMUNIT';
  state.completedUpgradeNames = options.completedUpgradeNames ?? [];
  state.statusBits = ['SELECTABLE'];
  state.geometryInfo = {
    ...state.geometryInfo,
    majorRadius: 8,
    minorRadius: 8,
    boundingCircleRadius: 8,
    boundingSphereRadius: 8,
  };
  state.visionRange = 150;
  state.shroudClearingRange = 150;
  state.shroudRange = 150;
  state.experienceTracker = {
    ...state.experienceTracker,
    currentLevel: 1,
    currentExperience: 150,
    experienceScalar: 1,
  };
  state.weaponSet = {
    version: 1,
    templateName,
    templateSetFlags: [],
    weapons: [
      {
        version: 3,
        templateName: 'TankGunPrimary',
        slot: 0,
        status: 0,
        ammoInClip: 1,
        whenWeCanFireAgain: 0,
        whenPreAttackFinished: 0,
        whenLastReloadStarted: 0,
        lastFireFrame: 0,
        suspendFXFrame: 0,
        projectileStreamObjectId: 0,
        maxShotCount: 0,
        currentBarrel: 0,
        numShotsForCurrentBarrel: 0,
        scatterTargetsUnused: [],
        pitchLimited: false,
        leechWeaponRangeActive: false,
      },
      {
        version: 3,
        templateName: 'TankGunSecondary',
        slot: 1,
        status: 0,
        ammoInClip: 1,
        whenWeCanFireAgain: 0,
        whenPreAttackFinished: 0,
        whenLastReloadStarted: 0,
        lastFireFrame: 0,
        suspendFXFrame: 0,
        projectileStreamObjectId: 0,
        maxShotCount: 0,
        currentBarrel: 0,
        numShotsForCurrentBarrel: 0,
        scatterTargetsUnused: [],
        pitchLimited: false,
        leechWeaponRangeActive: false,
      },
      {
        version: 3,
        templateName: 'TankGunTertiary',
        slot: 2,
        status: 0,
        ammoInClip: 1,
        whenWeCanFireAgain: 0,
        whenPreAttackFinished: 0,
        whenLastReloadStarted: 0,
        lastFireFrame: 0,
        suspendFXFrame: 0,
        projectileStreamObjectId: 0,
        maxShotCount: 0,
        currentBarrel: 0,
        numShotsForCurrentBarrel: 0,
        scatterTargetsUnused: [],
        pitchLimited: false,
        leechWeaponRangeActive: false,
      },
    ],
    currentWeapon: 0,
    currentWeaponLockedStatus: 0,
    filledWeaponSlotMask: 0b111,
    totalAntiMask: 0,
    hasDamageWeapon: true,
    totalDamageTypeMask: [],
  };
  state.constructionPercent = 100;
  state.layer = 1;
  state.destinationLayer = 1;
  state.isSelectable = true;
  state.specialPowerBits = [
    'SPECIAL_CASH_HACK',
    'SPECIAL_PARTICLE_UPLINK_CANNON',
    'SPECIAL_STALE_POWER',
  ];
  if (includeHelperModules) {
    state.modules = [
      {
        identifier: 'ModuleTag_DefectionHelper',
        blockData: createSourceDefectionHelperBlockData((99 << 2) | 2, 12, 88, 0.5, false),
      },
      {
        identifier: 'ModuleTag_FiringTrackerHelper',
        blockData: createSourceFiringTrackerBlockData((96 << 2) | 2, 2, 44, 96),
      },
      {
        identifier: 'ModuleTag_TempWeaponBonusHelper',
        blockData: createSourceTempWeaponBonusHelperBlockData((120 << 2) | 2, 4, 120),
      },
      {
        identifier: 'ModuleTag_SubdualDamageHelper',
        blockData: createSourceSubdualDamageHelperBlockData((77 << 2) | 2, 5),
      },
      {
        identifier: 'ModuleTag_SMCHelper',
        blockData: createSourceBaseOnlyObjectHelperBlockData((64 << 2) | 2),
      },
      {
        identifier: 'ModuleTag_RepulsorHelper',
        blockData: createSourceBaseOnlyObjectHelperBlockData((80 << 2) | 2),
      },
      {
        identifier: 'ModuleTag_StatusDamageHelper',
        blockData: createSourceStatusDamageHelperBlockData((90 << 2) | 2, 38, 90),
      },
      {
        identifier: 'ModuleTag_WeaponStatusHelper',
        blockData: createSourceBaseOnlyObjectHelperBlockData((55 << 2) | 3),
      },
    ];
  }
  if (extraModules.length > 0) {
    state.modules = [...state.modules, ...extraModules];
  }
  state.modulesReady = false;
  return new Uint8Array(buildSourceMapEntityChunk(state));
}

function createSourceGameLogicChunkData(
  includeHelperModules = false,
  extraModules: Array<{ identifier: string; blockData: Uint8Array }> = [],
  extraObjects: Array<{
    objectId: number;
    templateName: string;
    internalName?: string;
    teamId?: number;
    drawableId?: number;
    originalTeamName?: string;
    completedUpgradeNames?: string[];
  }> = [],
): Uint8Array {
  const xferSave = new XferSave();
  xferSave.open('create-source-game-logic-chunk');
  try {
    xferSave.xferVersion(3);
    xferSave.xferUnsignedInt(42);
    xferSave.xferVersion(1);
    const tocEntries = [{ templateName: 'RuntimeTank', tocId: 1 }];
    for (const object of extraObjects) {
      if (tocEntries.some((entry) => entry.templateName === object.templateName)) {
        continue;
      }
      tocEntries.push({ templateName: object.templateName, tocId: tocEntries.length + 1 });
    }
    xferSave.xferUnsignedInt(tocEntries.length);
    for (const tocEntry of tocEntries) {
      xferSave.xferAsciiString(tocEntry.templateName);
      xferSave.xferUnsignedShort(tocEntry.tocId);
    }
    xferSave.xferUnsignedInt(1 + extraObjects.length);
    xferSave.xferUnsignedShort(1);
    xferSave.beginBlock();
    xferSave.xferUser(createSourceObjectBlockData(includeHelperModules, extraModules));
    xferSave.endBlock();
    for (const object of extraObjects) {
      const tocId = tocEntries.find((entry) => entry.templateName === object.templateName)?.tocId;
      if (!tocId) {
        throw new Error(`Missing test TOC entry for ${object.templateName}`);
      }
      xferSave.xferUnsignedShort(tocId);
      xferSave.beginBlock();
      xferSave.xferUser(createSourceObjectBlockData(false, [], object));
      xferSave.endBlock();
    }

    xferSave.xferVersion(3);
    xferSave.xferAsciiString('america');
    xferSave.xferAsciiString('mission01');
    xferSave.xferInt(0);
    xferSave.xferInt(1);

    xferSave.xferUnsignedShort(0);
    xferSave.xferBool(false);
    xferSave.xferUnsignedInt(0);
    return new Uint8Array(xferSave.getBuffer());
  } finally {
    xferSave.close();
  }
}

function readSourceGameLogicObjectStates(data: ArrayBuffer) {
  const chunkData = readSaveChunkData(data, 'CHUNK_GameLogic');
  if (!chunkData) {
    return null;
  }
  const xferLoad = new XferLoad(chunkData.slice().buffer);
  xferLoad.open('read-source-game-logic-object-states');
  try {
    xferLoad.xferVersion(3);
    xferLoad.xferUnsignedInt(0);
    xferLoad.xferVersion(1);
    const tocCount = xferLoad.xferUnsignedInt(0);
    const tocById = new Map<number, string>();
    for (let index = 0; index < tocCount; index += 1) {
      const templateName = xferLoad.xferAsciiString('');
      const tocId = xferLoad.xferUnsignedShort(0);
      tocById.set(tocId, templateName);
    }
    const objectCount = xferLoad.xferUnsignedInt(0);
    const objects: Array<{ templateName: string | null; state: NonNullable<ReturnType<typeof parseSourceMapEntityChunk>> }> = [];
    for (let index = 0; index < objectCount; index += 1) {
      const tocId = xferLoad.xferUnsignedShort(0);
      const blockSize = xferLoad.beginBlock();
      const objectData = xferLoad.xferUser(new Uint8Array(blockSize)) as Uint8Array;
      xferLoad.endBlock();
      const parsed = parseSourceMapEntityChunk(objectData);
      if (parsed) {
        objects.push({
          templateName: tocById.get(tocId) ?? null,
          state: parsed,
        });
      }
    }
    return objects;
  } finally {
    xferLoad.close();
  }
}

function readFirstSourceGameLogicObjectState(data: ArrayBuffer) {
  return readSourceGameLogicObjectStates(data)?.[0]?.state ?? null;
}

