    expect(parsedToppleModule.angularAcceleration).toBeCloseTo(0.07, 5);
    expect(parsedToppleModule.toppleDirX).toBeCloseTo(-0.8, 5);
    expect(parsedToppleModule.toppleDirZ).toBeCloseTo(0.6, 5);
